from django.db.migrations.state import ProjectState
from django.db.migrations.autodetector import MigrationAutodetector
from django.db.migrations.questioner import MigrationQuestioner
from django.db import models

# Create initial state with UUIDField
initial_state = ProjectState()
initial_state.add_model_state(
    ('testapp1', 'App1'),
    {
        'fields': [
            ('id', models.UUIDField(primary_key=True)),
            ('text', models.CharField(max_length=100)),
            ('another_app', models.UUIDField(null=True, blank=True)),
        ],
    }
)
initial_state.add_model_state(
    ('testapp2', 'App2'),
    {
        'fields': [
            ('id', models.UUIDField(primary_key=True)),
            ('text', models.CharField(max_length=100)),
        ],
    }
)

# Create new state with ForeignKey
new_state = ProjectState()
new_state.add_model_state(
    ('testapp1', 'App1'),
    {
        'fields': [
            ('id', models.UUIDField(primary_key=True)),
            ('text', models.CharField(max_length=100)),
            ('another_app', models.ForeignKey('testapp2.App2', null=True, blank=True, on_delete=models.SET_NULL)),
        ],
    }
)
new_state.add_model_state(
    ('testapp2', 'App2'),
    {
        'fields': [
            ('id', models.UUIDField(primary_key=True)),
            ('text', models.CharField(max_length=100)),
        ],
    }
)

# Detect changes
questioner = MigrationQuestioner()
detector = MigrationAutodetector(initial_state, new_state, questioner)
changes = detector._detect_changes()

print('Changes detected:')
for app_label, migrations in changes.items():
